import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is GDP?", a: "GDP (Gross Domestic Product) is the total monetary value of all goods and services produced within a country's borders in a specific period. It is the most widely used measure of economic output and size." },
  { q: "What are the three approaches to calculating GDP?", a: "The expenditure approach: GDP = C + I + G + (X-M). The income approach: sum of all incomes earned. The production approach: sum of value added at each stage of production. All three methods yield the same result in theory." },
  { q: "What is GDP per capita?", a: "GDP per capita is GDP divided by the country's population. It gives a per-person measure of economic output and is commonly used to compare living standards between countries." },
  { q: "What is the difference between real and nominal GDP?", a: "Nominal GDP is calculated using current market prices. Real GDP is adjusted for inflation, allowing comparison across different time periods. Real GDP growth is a better indicator of true economic expansion." },
  { q: "What does negative net exports mean for GDP?", a: "When imports exceed exports (negative net exports or trade deficit), it reduces GDP by that amount. The US typically runs a trade deficit, meaning it imports more than it exports. This is the X-M component in the GDP formula." },
  { q: "What is the largest component of US GDP?", a: "Consumer spending (C) is the largest component of US GDP, accounting for approximately 68-70% of total GDP. Government spending (G) is second at about 17%. Investment (I) is third at about 18%, and net exports (X-M) is typically negative." },
  { q: "What is a recession and how is it defined by GDP?", a: "A recession is traditionally defined as two consecutive quarters of negative real GDP growth. The National Bureau of Economic Research (NBER) uses a broader definition that includes employment, income, and industrial production data." },
];

export default function GDPCalculator() {
  useCurrencyVersion();
  const [consumption, setConsumption] = useState(14000);
  const [investment, setInvestment] = useState(3500);
  const [govSpending, setGovSpending] = useState(3800);
  const [exports, setExports] = useState(2500);
  const [imports, setImports] = useState(3200);
  const [population, setPopulation] = useState(330);

  const gdp = consumption + investment + govSpending + (exports - imports);
  const netExports = exports - imports;
  const gdpPerCapita = (gdp / population) * 1000;

  const pctOf = (v: number) => gdp > 0 ? ((v / gdp) * 100).toFixed(1) : "-";

  return (
    <>
      <SEOHead
        title="Free GDP Calculator Online - Calculate Gross Domestic Product Instantly | CalcHive"
        description="Free online GDP calculator. Calculate Gross Domestic Product using the expenditure approach C + I + G + (X-M) instantly. 100% free for students and economists, no signup required."
        canonical="/gdp-calculator"
        keywords="free GDP calculator, gross domestic product calculator free online, expenditure approach GDP calculator free, calculate GDP free, economics GDP formula calculator free"
        category="Economics Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-cyan-600 dark:text-cyan-400 bg-cyan-50 dark:bg-cyan-950/50 px-3 py-1 rounded-full mb-4 inline-block">Economics</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free GDP Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free GDP calculator to calculate GDP free with the expenditure approach C + I + G + (X-M). This gross domestic product calculator free online also works as an expenditure approach GDP calculator free and economics GDP formula calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-5 mb-8">
            <SliderInput id="consumption" label="Consumer Spending / C" value={consumption} min={0} max={50000} step={100} onChange={setConsumption} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}B`} testId="input-consumption" />
            <SliderInput id="investment" label="Business Investment / I" value={investment} min={0} max={20000} step={100} onChange={setInvestment} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}B`} testId="input-investment" />
            <SliderInput id="gov" label="Government Spending / G" value={govSpending} min={0} max={20000} step={100} onChange={setGovSpending} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}B`} testId="input-gov" />
            <SliderInput id="exports" label="Exports / X" value={exports} min={0} max={20000} step={100} onChange={setExports} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}B`} testId="input-exports" />
            <SliderInput id="imports" label="Imports / M" value={imports} min={0} max={20000} step={100} onChange={setImports} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}B`} testId="input-imports" />
            <SliderInput id="population" label="Population (millions)" value={population} min={1} max={2000} step={1} onChange={setPopulation} format={v => `${v}M`} testId="input-population" />
          </div>
          <motion.div key={gdp} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-cyan-500 to-cyan-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">GDP</p>
              <p className="text-4xl font-black text-white tracking-tight" data-testid="result-gdp">{formatCurrencyValue(gdp, { maximumFractionDigits: 0 })}B</p>
              <p className="text-white/70 text-sm mt-1">C + I + G + (X - M)</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[
                { label: "Net Exports (X - M)", value: `${formatCurrencyValue(netExports, { maximumFractionDigits: 0 })}B`, red: netExports < 0 },
                { label: "GDP Per Capita", value: formatCurrencyValue(Math.round(gdpPerCapita), { maximumFractionDigits: 0 }) },
              ].map(({ label, value, red }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-base font-extrabold ${red ? "text-red-600 dark:text-red-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate GDP Using the Expenditure Approach for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The expenditure approach measures GDP by summing all spending on final goods and services in an economy. It is the most commonly taught and cited method for calculating GDP.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>GDP = C + I + G + (X - M)</p>
            <p className="text-xs text-muted-foreground mt-2">C = Consumer Spending (households)</p>
            <p className="text-xs text-muted-foreground">I = Business Investment (capital, inventory)</p>
            <p className="text-xs text-muted-foreground">G = Government Spending (excluding transfers)</p>
            <p className="text-xs text-muted-foreground">X = Exports, M = Imports, X- = Net Exports</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What is C + I + G + (X-M) in GDP Calculation</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Component", "Symbol", "Value", "% of GDP", "US Actual (2023)"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Consumer Spending", "C", `$${consumption.toLocaleString()}B`, `${pctOf(consumption)}%`, "~69%"],
                  ["Business Investment", "I", `$${investment.toLocaleString()}B`, `${pctOf(investment)}%`, "~18%"],
                  ["Government Spending", "G", `$${govSpending.toLocaleString()}B`, `${pctOf(govSpending)}%`, "~17%"],
                  ["Net Exports", "X-M", `$${netExports.toLocaleString()}B`, `${pctOf(netExports)}%`, "varies"],
                  ["Total GDP", "-", `$${gdp.toLocaleString()}B`, "100%", "$27,357B"],
                ].map(([comp, sym, val, pct, us]) => (
                  <tr key={comp} className="hover:bg-muted/30">
                    <td className="py-2.5 px-3 font-semibold text-foreground">{comp}</td>
                    <td className="py-2.5 px-3 text-cyan-600 dark:text-cyan-400 font-mono font-semibold">{sym}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{val}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{pct}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{us}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Gross Domestic Product Calculator for Students and Economists</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Country", "GDP (nominal)", "GDP Per Capita", "Growth Rate"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["United States", "$27.4T", "$82,000", "+2.5%"],
                  ["China", "$17.7T", "$12,500", "+5.2%"],
                  ["Germany", "$4.4T", "$52,800", "-0.3%"],
                  ["Japan", "$4.2T", "$33,900", "+1.9%"],
                  ["India", "$3.7T", "$2,600", "+8.2%"],
                  ["United Kingdom", "$3.1T", "$46,100", "+0.1%"],
                  ["France", "$3.0T", "$45,500", "+0.9%"],
                  ["World Total", "$105T", "$13,300", "+3.1%"],
                ].map(([country, gdpv, percap, growth]) => (
                  <tr key={country} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{country}</td>
                    <td className="py-2.5 px-4 text-cyan-600 dark:text-cyan-400 font-medium">{gdpv}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{percap}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{growth}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/gdp-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


